  create policy "Notifications delete self"
  on "public"."notifications"
  as permissive
  for delete
  to authenticated
using ((sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))));



  create policy "Notifications select self"
  on "public"."notifications"
  as permissive
  for select
  to authenticated
using ((sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))));



  create policy "Notifications update self"
  on "public"."notifications"
  as permissive
  for update
  to authenticated
using ((sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))))
with check ((sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))));


CREATE TRIGGER notify_on_community_comment_trigger AFTER INSERT ON public.community_comments FOR EACH ROW EXECUTE FUNCTION public.notify_on_community_comment();

CREATE TRIGGER notify_on_lead_assignment_trigger AFTER INSERT OR UPDATE OF sales_id ON public.contacts FOR EACH ROW EXECUTE FUNCTION public.notify_on_lead_assignment();

CREATE TRIGGER notify_on_payout_status_trigger AFTER UPDATE OF status ON public.deal_payouts FOR EACH ROW EXECUTE FUNCTION public.notify_on_payout_status();


